import React, { useState, useEffect } from 'react';

const App = () => {
  const [otp, setOtp] = useState('');
  const [qrCode1, setQrCode1] = useState('');
  const [qrCode2, setQrCode2] = useState('');
  const [qrCode3, setQrCode3] = useState('');
  const [isValid, setIsValid] = useState(false);

  useEffect(() => {
    const mockBackendApi = async () => {
      // Mock backend API to validate OTP
      const response = await fetch('/api/validate-otp', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ otp })
      });
      const data = await response.json();
      setIsValid(data.isValid);
    };
    mockBackendApi();
  }, [otp]);

  const handleOtpChange = (e) => {
    setOtp(e.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-full max-w-md">
        <h1 className="text-4xl font-bold mb-4">Authentication</h1>
        <div className="flex justify-center mb-4">
          <input
            type="number"
            value={otp}
            onChange={handleOtpChange}
            className="w-64 py-2 px-4 bg-[#C06C88] text-white rounded-lg"
          />
        </div>
        <div className="grid grid-cols-3 gap-4 mb-4">
          <button
            className="bg-[#C06C88] text-white rounded-lg p-2 w-24 h-24"
            onClick={() => setQrCode1('https://example.com/qrcode1')}
          >
            <svg width="24" height="24"><rect x="0" y="0" width="24" height="24" fill="#C06C88"/></svg>
          </button>
          <button
            className="bg-[#C06C88] text-white rounded-lg p-2 w-24 h-24"
            onClick={() => setQrCode2('https://example.com/qrcode2')}
          >
            <svg width="24" height="24"><rect x="0" y="0" width="24" height="24" fill="#C06C88"/></svg>
          </button>
          <button
            className="bg-[#C06C88] text-white rounded-lg p-2 w-24 h-24"
            onClick={() => setQrCode3('https://example.com/qrcode3')}
          >
            <svg width="24" height="24"><rect x="0" y="0" width="24" height="24" fill="#C06C88"/></svg>
          </button>
        </div>
        <p className="text-lg font-bold mb-4">OTP is {isValid ? 'valid' : 'invalid'}</p>
      </div>
    </div>
  );
};

export default App;
